module mux_2to1(
    input in0,          // 1-bit input.
    input in1,          // 1-bit input.
    input sel,          // 1-bit select signal.
    input en,           // Enable signal to activate the multiplexer.

    output out          // 1-bit output.
);

reg mux_2to1_out_r;

//------------------------------------------------
// Multiplexer logic
always @(*) begin
    if (en) begin
        case (sel)
            1'b0: mux_2to1_out_r = in0;
            1'b1: mux_2to1_out_r = in1;
            default: mux_2to1_out_r = 1'b0;
        endcase
    end else begin
        mux_2to1_out_r = 1'b0;
    end
end

assign out = mux_2to1_out_r;

endmodule
